import React, { useState, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../App';
import { API_URL } from '../config';

const Login = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [errorMsg, setErrorMsg] = useState('');
  const { login } = useContext(AuthContext);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setErrorMsg('');
    try {
      const res = await fetch(`${API_URL}/api/auth/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password }),
      });
      const data = await res.json();
      if (res.ok) {
        login(data.token);
        navigate('/');
      } else {
        setErrorMsg(data.msg || 'Login failed. Please check your credentials.');
      }
    } catch (err) {
      console.error(err);
      setErrorMsg('Server error. Please try again later.');
    }
  };

  return (
    <div className="form-container">
      <h2>Sign in</h2>
      {errorMsg && <div style={{ color: '#e30000', marginBottom: '15px', fontSize: '14px', fontWeight: 500 }}>{errorMsg}</div>}
      <form onSubmit={handleSubmit}>
        <input type="text" placeholder="Apple ID (Username)" value={username} onChange={(e) => setUsername(e.target.value)} required />
        <input type="password" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} required />
        <button type="submit">Continue</button>
      </form>
      <p>Don't have an account? <a href="/register">Create yours now.</a></p>
    </div>
  );
};

export default Login;
